import Link from "next/link";
import styles from "./contact.module.css";
import Image from "next/image";

function Contact() {
  return (
    <div className={styles.container}>
      <div>
        <Image
          src="/mail.png"
          alt="Picture of the author"
          width={60}
          height={60}
        />

        <Image
          src="/mail.png"
          alt="Picture of the author"
          width={70}
          height={70}
        />

        <Image
          src="/mail.png"
          alt="Picture of the author"
          width={70}
          height={70}
        />

        <Image
          src="/mail.png"
          alt="Picture of the author"
          width={70}
          height={70}
        />

        <Image
          src="/mail.png"
          alt="Picture of the author"
          width={70}
          height={70}
        />
      </div>
    </div>
  );
}

export default Contact;
